class Main {
    public static void main(String[] args) throws Exception {
        java.io.BufferedReader br = new java.io.BufferedReader(new java.io.InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            int n = Integer.parseInt(br.readLine().trim());
            int[] arr = new int[n];
            String[] parts = br.readLine().trim().split(" ");
            for (int i = 0; i < n; i++) arr[i] = Integer.parseInt(parts[i]);
            java.util.Arrays.sort(arr);
            java.util.List<java.util.List<Integer>> res = new java.util.ArrayList<>();
            backtrack(arr, 0, new java.util.ArrayList<>(), res);
            out.append('[');
            for (int i = 0; i < res.size(); i++) {
                java.util.List<Integer> subset = res.get(i);
                out.append('[');
                for (int j = 0; j < subset.size(); j++) {
                    out.append(subset.get(j));
                    if (j + 1 < subset.size()) out.append(", ");
                }
                out.append(']');
                if (i + 1 < res.size()) out.append(", ");
            }
            out.append(']');
            if (t + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
    private static void backtrack(int[] arr, int start, java.util.List<Integer> path, java.util.List<java.util.List<Integer>> res) {
        res.add(new java.util.ArrayList<>(path));
        for (int i = start; i < arr.length; i++) {
            if (i > start && arr[i] == arr[i - 1]) continue; // skip duplicates
            path.add(arr[i]);
            backtrack(arr, i + 1, path, res);
            path.remove(path.size() - 1);
        }
    }
}

